// COMPLETE, COMPILABLE C code
// Uses fast I/O and handles multiple test cases
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

// maximum N across all test cases (as per constraints)
#define MAXN 100000
#define MAXB 320   // ceil(sqrt(100000))

// structure for a small‑step sequence
typedef struct {
    int *idx;          // indices in the original array (0‑based)
    long long *pref;   // prefix sums of digit lengths
    int size;
} Seq;

int digit_len(int x) {
    if (x == 0) return 1;
    int cnt = 0;
    while (x) { cnt++; x /= 10; }
    return cnt;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        char **str = (char**)malloc(N * sizeof(char*));
        int *len = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) {
            scanf("%d", &A[i]);
            len[i] = digit_len(A[i]);
            str[i] = (char*)malloc(len[i] + 1);
            sprintf(str[i], "%d", A[i]);
        }
        int B = (int)ceil(sqrt((double)N));
        // allocate sequences for all v <= B
        Seq ***seq = (Seq***)malloc((B+1) * sizeof(Seq**));
        for (int v = 1; v <= B; ++v) {
            seq[v] = (Seq**)malloc(v * sizeof(Seq*));
            for (int r = 0; r < v; ++r) {
                // count how many elements belong to this (v,r)
                int cnt = 0;
                for (int pos = r; pos < N; pos += v) cnt++;
                seq[v][r] = (Seq*)malloc(sizeof(Seq));
                seq[v][r]->size = cnt;
                seq[v][r]->idx = (int*)malloc(cnt * sizeof(int));
                seq[v][r]->pref = (long long*)malloc(cnt * sizeof(long long));
                int p = 0;
                long long acc = 0;
                for (int pos = r; pos < N; pos += v) {
                    seq[v][r]->idx[p] = pos;
                    acc += len[pos];
                    seq[v][r]->pref[p] = acc;
                    ++p;
                }
            }
        }
        int M; scanf("%d", &M);
        while (M--) {
            int l, v, k; scanf("%d %d %d", &l, &v, &k);
            l--; // to 0‑based
            if (l >= N) { // empty progression
                printf("So sad\n");
                continue;
            }
            if (v <= B) {
                int r = l % v;
                Seq *s = seq[v][r];
                // find position of l inside this sequence
                int startPos = (l - r) / v; // 0‑based index in seq
                // binary search on prefix sums from startPos onward
                int lo = startPos, hi = s->size - 1, ans = -1;
                while (lo <= hi) {
                    int mid = (lo + hi) >> 1;
                    long long cur = s->pref[mid] - (startPos ? s->pref[startPos-1] : 0LL);
                    if (cur >= k) { ans = mid; hi = mid - 1; }
                    else lo = mid + 1;
                }
                if (ans == -1) {
                    printf("So sad\n");
                } else {
                    long long before = (ans==startPos) ? 0LL : (s->pref[ans-1] - (startPos ? s->pref[startPos-1] : 0LL));
                    int offset = k - (int)before - 1; // 0‑based inside the number
                    int idx = s->idx[ans];
                    printf("%c\n", str[idx][offset]);
                }
            } else {
                // large step – walk directly
                long long acc = 0;
                int answer = -1;
                for (int pos = l; pos < N; pos += v) {
                    if (acc + len[pos] >= k) {
                        int offset = k - (int)acc - 1;
                        answer = str[pos][offset];
                        break;
                    }
                    acc += len[pos];
                }
                if (answer == -1) printf("So sad\n");
                else printf("%c\n", (char)answer);
            }
        }
        // free memory
        for (int i = 0; i < N; ++i) free(str[i]);
        free(str); free(len); free(A);
        for (int v = 1; v <= B; ++v) {
            for (int r = 0; r < v; ++r) {
                free(seq[v][r]->idx);
                free(seq[v][r]->pref);
                free(seq[v][r]);
            }
            free(seq[v]);
        }
        free(seq);
    }
    return 0;
}

