// COMPLETE, COMPILABLE C++ code
// Handles multiple test cases and uses sqrt‑decomposition
#include <bits/stdc++.h>
using namespace std;

int digit_len(int x){
    if(x==0) return 1;
    int cnt=0; while(x){cnt++; x/=10;} return cnt;
}

struct Seq{
    vector<int> idx;          // positions (0‑based)
    vector<long long> pref;   // prefix sums of digit lengths
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> A(N);
        vector<string> str(N);
        vector<int> len(N);
        for(int i=0;i<N;++i){
            cin>>A[i];
            str[i]=to_string(A[i]);
            len[i]=str[i].size();
        }
        int B = (int)ceil(sqrt((double)N));
        // pre‑process for v <= B
        vector<vector<Seq>> table(B+1);
        for(int v=1; v<=B; ++v){
            table[v].assign(v, Seq());
            for(int r=0;r<v;++r){
                Seq &s = table[v][r];
                for(int pos=r; pos<N; pos+=v){
                    s.idx.push_back(pos);
                    long long cur = (s.pref.empty()?0:s.pref.back()) + len[pos];
                    s.pref.push_back(cur);
                }
            }
        }
        int M; cin>>M;
        while(M--){
            int l,v,k; cin>>l>>v>>k; --l; // 0‑based
            if(l>=N){ cout<<"So sad\n"; continue; }
            if(v<=B){
                int r = l % v;
                Seq &s = table[v][r];
                int startPos = (l - r)/v; // index inside seq
                int lo=startPos, hi=(int)s.idx.size()-1, ans=-1;
                while(lo<=hi){
                    int mid=(lo+hi)/2;
                    long long cur = s.pref[mid] - (startPos? s.pref[startPos-1]:0LL);
                    if(cur>=k){ ans=mid; hi=mid-1; }
                    else lo=mid+1;
                }
                if(ans==-1){ cout<<"So sad\n"; }
                else{
                    long long before = (ans==startPos)?0LL : (s.pref[ans-1] - (startPos? s.pref[startPos-1]:0LL));
                    int offset = k - (int)before - 1;
                    cout<<str[s.idx[ans]][offset]<<"\n";
                }
            }else{
                long long acc=0; char out='?'; bool found=false;
                for(int pos=l; pos<N; pos+=v){
                    if(acc + len[pos] >= k){
                        int offset = k - (int)acc - 1;
                        out = str[pos][offset];
                        found=true; break;
                    }
                    acc += len[pos];
                }
                if(found) cout<<out<<"\n"; else cout<<"So sad\n";
            }
        }
    }
    return 0;
}
